    "network:fetch",
    "wallet:sign"
  ],
  "web3": {
    "signers": ["hot"],
    "rpc": {
      "endpoints": ["https://eth-mainnet.g.alchemy.com/v2/${ALCHEMY_KEY}"]
    }
  },
  "inputs": {
    "strategy": {
      "type": "string",
      "required": true,
      "description": "Strategy preset: momentum, mean-reversion, or breakout"
    },
    "baseAsset": {
      "type": "string",
      "required": true,
      "description": "ERC-20 address of the base trading asset"
    },
    "maxNotionalUsd": {
      "type": "number",
      "required": false,
      "description": "Soft notional ceiling per position in USD"
    }
  },
