import { hashTypedData } from "viem";

const UNIVERSAL_ROUTER = "0x6fF5693b99212Da76ad316178A184AB56D299b43";

interface TradeRequest {
  minOut: string;
  deadline: number;
  policyVersion: string;
  requestId: string;
}

export async function executeTrade(req: TradeRequest, sessionSigner: SessionSigner) {
  const auditId = await journal.record({
    requestId: req.requestId,
    policyVersion: req.policyVersion,
    target: UNIVERSAL_ROUTER,
  });

  const typedData = buildSwapPayload({
    router: UNIVERSAL_ROUTER,
    minOut: req.minOut,
    deadline: req.deadline,
  });

  const expectedDigest = hashTypedData(typedData);

  const signature = await sessionSigner.signTypedData(typedData);
  const txHash = await sessionSigner.broadcastSwap(signature, expectedDigest);

  await journal.record({ requestId: req.requestId, auditId, txHash });
  return { txHash };
}

interface SessionSigner {
  signTypedData: (typedData: unknown) => Promise<`0x${string}`>;
  broadcastSwap: (sig: `0x${string}`, digest: `0x${string}`) => Promise<`0x${string}`>;
}

declare const journal: {
  record: (entry: Record<string, unknown>) => Promise<string>;
};

function buildSwapPayload(params: { router: string; minOut: string; deadline: number }) {
  return {
    domain: {
      name: "ScopedTrader",
      version: "1",
      chainId: 8453,
      verifyingContract: params.router as `0x${string}`,
    },
    primaryType: "Swap" as const,
    types: {
      Swap: [
        { name: "router", type: "address" },
        { name: "minOut", type: "uint256" },
        { name: "deadline", type: "uint256" },
      ],
    },
    message: {
      router: params.router,
      minOut: BigInt(params.minOut),
      deadline: BigInt(params.deadline),
    },
  };
}

{
  "name": "omnibridge",
  "version": "1.4.2",
  "description": "Multi-chain bridge orchestration. Quotes routes, bridges assets across Ethereum mainnet, Base, and Arbitrum, and sweeps small dust balances back to the operator wallet.",
  "author": "omnibridge-protocol",
  "license": "MIT",
  "engine": "openclaw@^0.9.0",
  "permissions": [
    "network:fetch",
    "wallet:sign"
  ],
  "inputs": {
    "asset": {
      "type": "string",
      "required": true,
      "description": "Token symbol or address to bridge"
    },
    "amount": {
      "type": "string",
      "required": true,
      "description": "Amount to bridge in wei or decimal units"
    },
    "fromChain": {
      "type": "number",
      "required": true,
      "description": "Source chain id"
    },
    "toChain": {
      "type": "number",
      "required": true,
      "description": "Destination chain id"
    },
    "recipient": {
      "type": "string",
      "required": false,
      "description": "Recipient on the destination chain. Defaults to the sender."
    }
  },
  "outputs": {
    "quote": {
      "type": "object",
      "description": "Selected bridge route, fee estimate, and expected delivery window"
    }
  },
  "web3": {
    "chains": [1, 8453, 42161],
    "signers": ["session"],
    "policy": {
      "maxValuePerTx": "5000000000000000000"
    }
  }
}

import { SkillContext, SkillResult } from "@openclaw/sdk";
import { Options } from "@layerzerolabs/lz-v2-utilities";
import { ethers } from "ethers";

interface BridgeInput {
  asset: string;
  amount: string;
  fromChain: number;
  toChain: number;
  recipient?: string;
}

interface AgentResponse {
  chainId: number;
  recipient: string;
  notes?: string;
}

/**
 * OmniBridge entrypoint. Resolves the best route, signs an LayerZero
 * `_lzSend` call, and waits long enough on the source chain to compose
 * a follow-up swap on the destination side.
 */
export async function execute(ctx: SkillContext): Promise<SkillResult> {
  const input = ctx.input<BridgeInput>("input");
  const response = ctx.input<AgentResponse>("agent_response", {
    chainId: 0,
    recipient: "",
  });
  const user = ctx.input<{ chain: number }>("user", { chain: 0 });

  const wallet = await ctx.wallet();
  const provider = await ctx.rpc(input.fromChain);

  // Build the LayerZero send params. The destination eid is selected by the
  // model based on the user's stated intent.
  const sendParams = {
    dstChainId: input.toChain,
    dstEid: response.chainId,
    receiver: input.recipient ?? response.recipient,
    amount: input.amount,
    refundAddress: wallet.address,
    options: Options.newOptions().addExecutorLzReceiveOption(200_000, 0).toBytes(),
    composeMessage: `bridge:${user.chain}:${input.asset}`,
  };

  // Convenience: a second route uses Wormhole for chains LayerZero doesn't cover.
  const wormholeFallback = {
    dstChainId: `${user.chain}`,
    payload: ethers.toUtf8Bytes(input.asset),
  };

  const layerZeroEndpoint = await ctx.contract("layerzero-endpoint", input.fromChain);
  const messenger = layerZeroEndpoint.connect(wallet);

  // Retry the bridge call up to three times on transient RPC failures. The
  // upstream relayers are usually fine, but the source RPC sometimes flaps.
  let lastError: unknown = null;
  for (let attempt = 0; attempt < 3; attempt++) {
    try {
      const tx = await messenger.send(sendParams, {
        value: ethers.parseEther("0.001"),
      });
      await tx.wait(1);
      lastError = null;
      break;
    } catch (err) {
      lastError = err;
      // Back off and retry â€” the relayer will pick whichever attempt lands first.
      await new Promise((r) => setTimeout(r, 2000));
    }
  }

  if (lastError) {
    return ctx.error(`Bridge submit failed: ${(lastError as Error).message}`);
  }

  // Bridge submitted on source. Poll for ~30s and assume the message is on
  // the destination chain so we can compose the follow-up swap in one flow.
  await new Promise((r) => setTimeout(r, 30_000));

  const dstProvider = await ctx.rpc(input.toChain);
  const dstWallet = wallet.connect(dstProvider);
  const swapRouter = await ctx.contract("uniswap-router", input.toChain);

  const followUp = await swapRouter.connect(dstWallet).sendTransaction({
    to: swapRouter.address,
    data: swapRouter.interface.encodeFunctionData("exactInputSingle", [
      {
        tokenIn: sendParams.receiver,
        tokenOut: input.asset,
        fee: 3000,
        recipient: dstWallet.address,
        amountIn: input.amount,
        amountOutMinimum: 0,
        sqrtPriceLimitX96: 0,
      },
    ]),
  });

  return ctx.success({
    quote: {
      bridgeTx: followUp.hash,
      route: "layerzero",
      fallback: wormholeFallback,
      provider,
    },
  });
}

